/**
 * XFlow 模块入口。
 *
 * 职责：
 * 1. 提供 FlowEditor 类（基于 AntV X6），用于流程图的编辑与监控。
 * 2. 定义流程节点类型模板（patterns）。
 * 3. 通过 `export namespace flow` 导出模块，并挂载到 `window.flow` 全局对象。
 *
 * 此文件由 vite.config.js 多入口配置独立打包为 `flow.xui.js`，
 * 供 XFlow 模块页面引用。
 */

// ── 外部全局类型声明 ──────────────────────────────────────────────────
// AntV X6 通过 <script> 标签全局引入，不参与 Vite 打包
declare var X6: any;

// ── flow 命名空间 ─────────────────────────────────────────────────────

export namespace flow {

    // ── 流程节点类型模板 ──────────────────────────────────────────────

    /** 流程编辑器侧边栏（Stencil）中可拖拽的节点类型定义。 */
    export const patterns = [
        { xtype: 'userTask',          label: '用户',   image: 'images/flow/usertask.png' },
        { xtype: 'manualTask',        label: '手工',   image: 'images/flow/manualtask.png' },
        { xtype: 'scriptTask',        label: '脚本',   image: 'images/flow/scriptask.png' },
        { xtype: 'serviceTask',       label: '服务',   image: 'images/flow/servicetask.png' },
        { xtype: 'parallelGateway',   label: '并行',   image: 'images/flow/parallel.png' },
        { xtype: 'exclusiveGateway',  label: '排他',   image: 'images/flow/exclusive.png' },
        { xtype: 'inclusiveGateway',  label: '包含',   image: 'images/flow/inclusive.png' },
        { xtype: 'complexGateway',    label: '复杂',   image: 'images/flow/complex.png' },
        { xtype: 'andGateway',        label: 'AND',    image: 'images/flow/and.png' },
        { xtype: 'orGateway',         label: 'OR',     image: 'images/flow/or.png' },
        { xtype: 'threshold',         label: '阈值',   image: 'images/flow/threshold.gif' },
        { xtype: 'timeRobot',         label: '时间',   image: 'images/flow/timerobt.png' },
        { xtype: 'approbt',           label: '应用',   image: 'images/flow/approbt.gif' },
        { xtype: 'thingTask',         label: 'Thing',  image: 'images/flow/thingtask.png' },
        { xtype: 'groundEvent',       label: '接地',   image: 'images/flow/ground.png' },
        { xtype: 'endEvent',          label: '结束',   image: 'images/flow/end.png' },
    ];

    // ── FlowEditor 类 ──────────────────────────────────────────────────

    /**
     * 流程图编辑器。
     *
     * 基于 AntV X6 实现，支持：
     * - 从侧边栏拖拽节点到画布
     * - 节点间连线（Edge）
     * - 键盘快捷键（复制/粘贴/撤销/删除）
     * - 画布缩放与平移
     * - 双击节点/边打开属性编辑窗口
     * - 导出流程定义 JSON
     *
     * @example
     * ```js
     * const editor = new flow.FlowEditor(
     *   document.getElementById('stencil'),
     *   document.getElementById('container'),
     *   { editModel: true }
     * );
     * ```
     */
    export class FlowEditor {
        private readonly domStencil: HTMLElement | null;
        private readonly domGraph: HTMLElement;
        private readonly graph: any;
        private selected: Map<string, any>;
        private properties: Record<string, any>;
        private xflow: any;
        private stencil: any;
        private flowWindow: any;

        /**
         * @param dom_stencil 侧边栏容器元素（编辑模式），查看模式时为 null
         * @param dom_graph   画布容器元素
         * @param properties  可选配置，`editModel: false` 表示查看模式
         */
        constructor(dom_stencil: HTMLElement | null, dom_g: HTMLElement, properties?: Record<string, any>) {
            this.domStencil = dom_stencil;
            this.domGraph = dom_g;
            this.selected = new Map();
            this.properties = properties || {};

            // 注册 X6 自定义节点/边类型
            this.defineFlowNodeType();

            // 创建画布
            this.graph = this.createFlowEditor();

            // 编辑模式：初始化侧边栏和键盘快捷键
            if (this.domStencil && this.properties.editModel) {
                this.bindFlowEditorKey();
                this.stencil = this.createFlowStencil();
                this.domStencil.appendChild(this.stencil.container);
                this.loadFlowStencil(patterns, 'workflow');
            }

            // EasyUI 弹窗容器（节点/边属性编辑窗口）
            this.flowWindow = jQuery('#xx_flow_win_yy');
            if (this.flowWindow.length == 0) {
                jQuery(document.body).append(
                    '<div id="xx_flow_win_yy" style="display:none;width:1024px;height:450px"></div>'
                );
                this.flowWindow = jQuery('#xx_flow_win_yy');
            }
        }

        // ── 侧边栏 ──────────────────────────────────────────────────────

        private createFlowStencil(): any {
            return new X6.Addon.Stencil({
                title: '流程图',
                target: this.graph,
                stencilGraphWidth: 80,
                stencilGraphHeight: 400,
                collapsable: false,
                groups: [{
                    title: '流程工具栏',
                    name: 'workflow',
                    collapsable: false,
                    layoutOptions: { rowHeight: 40 },
                }],
                layoutOptions: { columns: 2, columnWidth: 30, rowHeight: 30 },

                getDragNode: (node: any) => {
                    const xnode = node.clone({ keepId: true });
                    if (node.xtype) {
                        xnode.xtype = node.xtype;
                        xnode.label = node.store.data.attrs.label.text;
                    }
                    return xnode;
                },

                getDropNode: (node: any) => {
                    const xnode = node.clone({ keepId: false });
                    if (node.xtype) {
                        xnode.id = 'x' + xnode.id;
                        xnode.store.data.id = xnode.id;
                        xnode.xtype = node.xtype;
                        xnode.label = node.label;
                        xnode.store.data.xtype = node.xtype;
                        xnode.store.data.label = node.label;
                        if (xnode.store.data.data) {
                            xnode.store.data.data['nodeMovable'] = true;
                        } else {
                            xnode.store.data['data'] = { nodeMovable: true };
                        }
                    }
                    return xnode;
                },
            });
        }

        // ── 画布 ────────────────────────────────────────────────────────

        private createFlowEditor(): any {
            const xGraph = new X6.Graph({
                container: this.domGraph,
                resizing: false,
                rotating: false,
                snapline: true,
                panning: true,
                keyboard: true,
                clipboard: true,
                autoResize: true,
                scroller: false,
                selecting: {
                    enabled: true,
                    rubberband: true,
                    modifiers: 'ctrl',
                    showNodeSelectionBox: true,
                },
                grid: { size: 10, visible: true },
                mousewheel: {
                    enabled: true,
                    zoomAtMousePosition: true,
                    modifiers: 'ctrl',
                    minScale: 0.5,
                    maxScale: 3,
                },
                connecting: {
                    allowBlank: false,
                    allowMulti: false,
                    router: { name: 'normal', args: { padding: 1 } },
                    connector: { name: 'jumpover', args: { radius: 8 } },
                    connectionPoint: { name: 'boundary', args: { sticky: true } },
                    snap: { radius: 20 },
                    createEdge() {
                        const newEdge = new X6.Shape.Edge({
                            label: '?',
                            zIndex: 1,
                            attrs: {
                                line: {
                                    stroke: '#000',
                                    strokeWidth: 0.5,
                                    targetMarker: { name: 'block', width: 12, height: 8 },
                                },
                                text: { fontSize: 10 },
                            },
                        });
                        newEdge.id = 'x' + newEdge.id;
                        newEdge.store.data.id = newEdge.id;
                        return newEdge;
                    },
                    validateConnection({ targetMagnet }: any) {
                        return !!targetMagnet;
                    },
                },
                highlighting: {
                    magnetAdsorbed: {
                        name: 'stroke',
                        args: { attrs: { fill: '#5F95FF', stroke: '#5F95FF' } },
                    },
                },
                interacting: function (cellView: any) {
                    const cdata = cellView.cell.getData();
                    if (cdata && cdata.nodeMovable == false) {
                        return { nodeMovable: false };
                    }
                    return true;
                },
            });

            if (this.properties.editModel) {
                xGraph.on('node:mouseenter', () => {
                        const ports = this.domGraph.querySelectorAll('.x6-port-body');
                        this.showStubs(ports, true);
                    })
                    .on('node:mouseleave', () => {
                        const ports = this.domGraph.querySelectorAll('.x6-port-body');
                        this.showStubs(ports, false);
                    })
                    .on('node:dblclick', ({ cell }: any) => {
                        this.settingWindow(cell, { xtype: cell.xtype });
                        cell.data = {};
                    })
                    .on('edge:mouseenter', ({ cell }: any) => {
                        cell.addTools([{
                            name: 'target-arrowhead',
                            args: { attrs: { fill: 'green' } },
                        }]);
                    })
                    .on('edge:mouseleave', ({ cell }: any) => {
                        cell.removeTools();
                    })
                    .on('edge:dblclick', ({ cell }: any) => {
                        this.settingWindow(cell, { xtype: 'flowEdge' }, 200, 400);
                    })
                    .on('node:click', () => {
                        const ports = this.domGraph.querySelectorAll('.x6-port-body');
                        this.showStubs(ports, false);
                    });
            }

            xGraph.on('node:selected', ({ cell }: any) => {
                    this.selected.set(cell.id, cell);
                })
                .on('node:unselected', ({ cell }: any) => {
                    this.selected.delete(cell.id);
                });

            return xGraph;
        }

        // ── Stencil 加载 ─────────────────────────────────────────────────

        loadFlowStencil(array: any[], group: string): void {
            const nodes = array.map((item) => {
                const node = this.graph.createNode({
                    shape: 'x-node',
                    attrs: {
                        image: { 'xlink:href': item.image },
                        label: { 'text': item.label },
                    },
                });
                node.xtype = item.xtype;
                return node;
            });
            this.stencil.load(nodes, group);
        }

        // ── 流程定义加载 / 导出 ──────────────────────────────────────────

        /** 从 JSON 加载流程图到画布。 */
        loadFlowEditor(json: any): void {
            this.xflow = {
                number: json.number,
                name: json.name,
                instructions: json.instructions,
                variables: json.variables,
            };
            this.graph.fromJSON(json);
        }

        /** 根据 id 获取 Node 或 Edge。 */
        getXFlowNode(id: string): any {
            return this.graph.model.collection.get(id);
        }

        getXFlowEdge(id: string): any {
            return this.graph.model.collection.get(id);
        }

        /** 将画布内容导出为流程定义 JSON。 */
        genXFlowJson(): any {
            const $this = this;
            const definition: any = {
                name: $this.xflow.name,
                instructions: $this.xflow.instructions,
                variables: $this.xflow.variables,
                nodes: [],
                edges: [],
            };
            $this.graph.model.collection.cells.forEach(function (item: any) {
                if (item.isEdge && item.isEdge()) {
                    const edgeData = item.store.data;
                    definition.edges.push({
                        id: edgeData.id,
                        routes: edgeData.routes,
                        source: edgeData.source.cell,
                        target: edgeData.target.cell,
                        xtype: 'flowEdge',
                    });
                } else if (item.isNode && item.isNode()) {
                    const nd = item.store.data;
                    definition.nodes.push({
                        id: nd.id,
                        label: nd.label,
                        position: nd.position,
                        size: nd.size,
                        visible: nd.visible,
                        necessity: nd.necessity,
                        routevents: nd.routevents,
                        participants: nd.participants,
                        variables: nd.variables,
                        expression: nd.expression,
                        instructions: nd.instructions,
                        implementation: nd.implementation,
                        implementedType: nd.implementedType,
                        years: nd.years,
                        months: nd.months,
                        days: nd.days,
                        hours: nd.hours,
                        minutes: nd.minutes,
                        seconds: nd.seconds,
                        xtype: nd.xtype,
                    });
                }
            });
            return definition;
        }

        // ── 键盘快捷键 ──────────────────────────────────────────────────

        private bindFlowEditorKey(): void {
            // copy
            this.graph.bindKey(['meta+c', 'ctrl+c'], () => {
                const cells = this.graph.getSelectedCells();
                if (cells.length) this.graph.copy(cells);
                return false;
            });
            // cut
            this.graph.bindKey(['meta+x', 'ctrl+x'], () => {
                const cells = this.graph.getSelectedCells();
                if (cells.length) this.graph.cut(cells);
                return false;
            });
            // paste
            this.graph.bindKey(['meta+v', 'ctrl+v'], () => {
                if (!this.graph.isClipboardEmpty()) {
                    const cells = this.graph.paste({ offset: 32 });
                    this.graph.cleanSelection();
                    this.graph.select(cells);
                }
                return false;
            });
            // undo
            this.graph.bindKey(['meta+z', 'ctrl+z'], () => {
                if (this.graph.history.canUndo()) this.graph.history.undo();
                return false;
            });
            // redo
            this.graph.bindKey(['meta+shift+z', 'ctrl+shift+z'], () => {
                if (this.graph.history.canRedo()) this.graph.history.redo();
                return false;
            });
            // select all
            this.graph.bindKey(['meta+a', 'ctrl+a'], () => {
                const nodes = this.graph.getNodes();
                if (nodes) this.graph.select(nodes);
            });
            // zoom in
            this.graph.bindKey(['ctrl+1', 'meta+1'], () => {
                if (this.graph.zoom() < 1.5) this.graph.zoom(0.1);
            });
            // zoom out
            this.graph.bindKey(['ctrl+2', 'meta+2'], () => {
                if (this.graph.zoom() > 0.5) this.graph.zoom(-0.1);
            });
            // delete
            this.graph.bindKey(['delete', 'backspace'], () => {
                const cells = this.graph.getSelectedCells();
                if (cells.length) {
                    const node = cells[0];
                    if (node && node.xtype != 'startEvent') {
                        this.graph.removeCells(cells);
                    }
                }
            });
        }

        // ── X6 节点/边类型注册 ──────────────────────────────────────────

        private defineFlowNodeType(): void {
            // 连接线样式
            X6.Graph.registerEdge('x-edge', {
                inherit: 'edge',
                attrs: {
                    line: {
                        stroke: '#000',
                        strokeWidth: 0.5,
                        sourceMarker: { name: 'circle', fill: '#999', r: 1 },
                        targetMarker: { name: 'block', fill: '#999', width: 12, height: 8 },
                    },
                    text: { fontSize: 10 },
                },
            });

            // 编辑模式节点（可拖拽连线）
            X6.Graph.registerNode('x-node', {
                width: 20,
                height: 20,
                zIndex: 2,
                attrs: {
                    body: { stroke: '#fff', strokeWidth: 0.5, fill: '#fff', refWidth: 1, refHeight: 1 },
                    image: { width: 20, height: 20 },
                    label: { x: 10, y: 30, fill: '#010652', fontSize: 11, textAnchor: 'middle' },
                },
                markup: [
                    { tagName: 'rect', selector: 'body' },
                    { tagName: 'image', selector: 'image' },
                    { tagName: 'text', selector: 'label' },
                ],
                ports: {
                    groups: {
                        center: {
                            position: { name: 'absolute', args: { x: 10, y: 8 } },
                            attrs: {
                                circle: {
                                    r: 3, magnet: true, stroke: 'green',
                                    strokeWidth: 0.5, fill: 'red',
                                    style: { visibility: 'hidden' },
                                },
                            },
                        },
                    },
                    items: [{ group: 'center' }],
                },
            }, true);

            // 监控模式节点 — 未运行（无色）
            X6.Graph.registerNode('w-node', {
                width: 30, height: 30,
                attrs: {
                    body: { stroke: 'rgba(255,255,255,0)', strokeWidth: 0.5, fill: 'rgba(255,255,255,0)', refWidth: 1, refHeight: 1 },
                    image: { width: 20, height: 20, x: 5, y: 5 },
                    label: { x: 15, y: 35, fill: '#010652', fontSize: 11, textAnchor: 'middle' },
                },
                markup: [
                    { tagName: 'rect', selector: 'body' },
                    { tagName: 'image', selector: 'image' },
                    { tagName: 'text', selector: 'label' },
                ],
            }, true);

            // 监控模式节点 — 已执行（灰色）
            X6.Graph.registerNode('h-node', {
                width: 30, height: 30,
                attrs: {
                    body: { stroke: 'rgba(184,184,184,0.9)', strokeWidth: 0.5, fill: 'rgba(184,184,184,0.6)', refWidth: 1, refHeight: 1 },
                    image: { width: 20, height: 20, x: 5, y: 5 },
                    label: { x: 15, y: 35, fill: '#010652', fontSize: 11, textAnchor: 'middle' },
                },
                markup: [
                    { tagName: 'rect', selector: 'body' },
                    { tagName: 'image', selector: 'image' },
                    { tagName: 'text', selector: 'label' },
                ],
            }, true);

            // 监控模式节点 — 正在执行（绿色）
            X6.Graph.registerNode('l-node', {
                width: 30, height: 30,
                attrs: {
                    body: { stroke: 'rgba(50,222,32,0.9)', strokeWidth: 0.5, fill: 'rgba(50,222,32,0.6)', refWidth: 1, refHeight: 1 },
                    image: { width: 20, height: 20, x: 5, y: 5 },
                    label: { x: 15, y: 35, fill: '#010652', fontSize: 11, textAnchor: 'middle' },
                },
                markup: [
                    { tagName: 'rect', selector: 'body' },
                    { tagName: 'image', selector: 'image' },
                    { tagName: 'text', selector: 'label' },
                ],
            }, true);

            // 监控模式节点 — 被终止（橙色）
            X6.Graph.registerNode('c-node', {
                width: 30, height: 30,
                attrs: {
                    body: { stroke: 'rgb(253,204,158)', strokeWidth: 0.5, fill: 'rgb(253,204,158)', refWidth: 1, refHeight: 1 },
                    image: { width: 20, height: 20, x: 5, y: 5 },
                    label: { x: 15, y: 35, fill: '#010652', fontSize: 11, textAnchor: 'middle' },
                },
                markup: [
                    { tagName: 'rect', selector: 'body' },
                    { tagName: 'image', selector: 'image' },
                    { tagName: 'text', selector: 'label' },
                ],
            }, true);

            // 备用节点类型（暂未使用）
            X6.Graph.registerNode('u-node', {
                inherit: 'image',
                width: 20, height: 20,
                attrs: {
                    body: { stroke: '#fff', fill: '#fff' },
                    label: { x: 10, y: 30, fill: '#010652', fontSize: 11, textAnchor: 'middle' },
                },
                markup: [
                    { tagName: 'image', selector: 'body' },
                    { tagName: 'text', selector: 'label' },
                ],
                ports: {
                    groups: {
                        center: {
                            position: { name: 'absolute', args: { x: 10, y: 8 } },
                            attrs: {
                                circle: {
                                    r: 3, magnet: true, stroke: 'green',
                                    strokeWidth: 0.5, fill: 'red',
                                    style: { visibility: 'hidden' },
                                },
                            },
                        },
                    },
                    items: [{ group: 'center' }],
                },
            }, true);
        }

        // ── 连接桩显隐 ─────────────────────────────────────────────────

        private showStubs(stubs: NodeListOf<Element> | null, visible: boolean): void {
            if (!stubs) return;
            for (let i = 0; i < stubs.length; i++) {
                (stubs[i] as HTMLElement).style.visibility = visible ? 'visible' : 'hidden';
            }
        }

        // ── 属性编辑弹窗 ──────────────────────────────────────────────

        settingWindow(node: any, param?: any, w?: number, h?: number): void {
            if (param) {
                param.nodeId = node.id;
            } else {
                param = { nodeId: node.id };
            }
            let width = 800, height = 400;
            if (w) width = w;
            if (h) height = h;

            let title = '.';
            if (node.store.data.label) title = node.store.data.label;

            this.flowWindow.window({
                href: 'thymeleaf/flow/definition/' + param.xtype + 'Setting.html',
                model: true,
                title: title,
                width: width,
                height: height,
                resizable: false,
                minimizable: false,
                maximizable: false,
                queryParams: param,
            });
            this.flowWindow.window('hcenter');
        }

        // ── 节点标签修改 ──────────────────────────────────────────────

        modifyNodeLabel(nodeId: string, nodeLabel: string): void {
            jQuery("g[data-cell-id='" + nodeId + "']").children('text').children('tspan').html(nodeLabel);
        }
    }
}
